import { useState } from 'react';
import { useAuth } from '../context/AuthContext';

const AdminDashboard = () => {
  const { user } = useAuth();
  const [activeTab, setActiveTab] = useState('posts');
  
  // Data States
  const [posts, setPosts] = useState([
    { id: 1, title: 'bsxjshbjcs', author: 'glaiza', status: 'PUBLISHED' },
    { id: 2, title: 'BlackPink', author: 'glaiza', status: 'PUBLISHED' },
  ]);
  
  const [members, setMembers] = useState([
    { id: 1, name: 'glaiza', role: 'User' },
    { id: 2, name: 'Edrick', role: 'Admin' },
  ]);

  // Form State para sa bagong post
  const [newTitle, setNewTitle] = useState('');

  const handleAddPost = (e) => {
    e.preventDefault();
    if (!newTitle) return;

    const newPost = {
      id: Date.now(),
      title: newTitle,
      author: user?.email.split('@')[0] || 'admin', // Kinukuha ang name sa email
      status: 'PUBLISHED'
    };

    setPosts([newPost, ...posts]);
    setNewTitle('');
    alert('Post added successfully!');
  };

  const handleRemovePost = (id) => {
    if (window.confirm('Remove this post?')) {
      setPosts(posts.filter(p => p.id !== id));
    }
  };

  return (
    <div style={{ backgroundColor: '#fce4ec', minHeight: '100vh', padding: '40px 20px' }}>
      <div style={{ maxWidth: '900px', margin: '0 auto', backgroundColor: 'white', padding: '30px', borderRadius: '20px', boxShadow: '0 10px 25px rgba(0,0,0,0.05)' }}>
        
        <h1 style={{ textAlign: 'center', color: '#880e4f', fontFamily: 'serif', marginBottom: '30px' }}>Admin Dashboard</h1>

        {/* Tab Buttons */}
        <div style={{ display: 'flex', justifyContent: 'center', gap: '15px', marginBottom: '30px' }}>
          <button 
            onClick={() => setActiveTab('members')}
            style={{ border: 'none', background: activeTab === 'members' ? '#ff69b4' : '#f8bbd0', color: 'white', padding: '10px 25px', borderRadius: '25px', cursor: 'pointer', fontWeight: 'bold' }}
          >
            Members ({members.length})
          </button>
          <button 
            onClick={() => setActiveTab('posts')}
            style={{ border: 'none', background: activeTab === 'posts' ? '#ff69b4' : '#f8bbd0', color: 'white', padding: '10px 25px', borderRadius: '25px', cursor: 'pointer', fontWeight: 'bold' }}
          >
            All Posts ({posts.length})
          </button>
        </div>

        {activeTab === 'posts' ? (
          <>
            {/* Quick Add Post Form */}
            <form onSubmit={handleAddPost} style={{ marginBottom: '20px', display: 'flex', gap: '10px' }}>
              <input 
                type="text" 
                placeholder="Write a new post title..." 
                value={newTitle}
                onChange={(e) => setNewTitle(e.target.value)}
                style={{ flex: 1, padding: '10px', borderRadius: '10px', border: '1px solid #ddd' }}
              />
              <button type="submit" style={{ backgroundColor: '#ff1493', color: 'white', border: 'none', padding: '10px 20px', borderRadius: '10px', cursor: 'pointer' }}>
                Post
              </button>
            </form>

            {/* Posts Table */}
            <div style={{ borderRadius: '15px', overflow: 'hidden', border: '1px solid #f8bbd0' }}>
              <table style={{ width: '100%', borderCollapse: 'collapse' }}>
                <thead>
                  <tr style={{ backgroundColor: '#ff1493', color: 'white' }}>
                    <th style={{ padding: '15px', textAlign: 'left' }}>TITLE</th>
                    <th style={{ padding: '15px', textAlign: 'left' }}>AUTHOR</th>
                    <th style={{ padding: '15px', textAlign: 'left' }}>STATUS</th>
                    <th style={{ padding: '15px', textAlign: 'center' }}>ACTION</th>
                  </tr>
                </thead>
                <tbody>
                  {posts.map(post => (
                    <tr key={post.id} style={{ borderBottom: '1px solid #fce4ec' }}>
                      <td style={{ padding: '15px' }}>{post.title}</td>
                      <td style={{ padding: '15px' }}>{post.author}</td>
                      <td style={{ padding: '15px' }}>
                        <span style={{ backgroundColor: '#e8f5e9', color: '#2e7d32', padding: '5px 12px', borderRadius: '15px', fontSize: '12px', fontWeight: 'bold' }}>
                          {post.status}
                        </span>
                      </td>
                      <td style={{ padding: '15px', textAlign: 'center' }}>
                        <button onClick={() => handleRemovePost(post.id)} style={{ backgroundColor: '#ff4d4d', color: 'white', border: 'none', padding: '6px 15px', borderRadius: '20px', cursor: 'pointer' }}>
                          Remove
                        </button>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </>
        ) : (
          <div style={{ textAlign: 'center', color: '#880e4f' }}>
            <h3>Member List</h3>
            <ul style={{ listStyle: 'none', padding: 0 }}>
              {members.map(m => <li key={m.id} style={{ padding: '10px', borderBottom: '1px solid #eee' }}>{m.name} - <b>{m.role}</b></li>)}
            </ul>
          </div>
        )}
      </div>
    </div>
  );
};

export default AdminDashboard;
